/**
 * MedX spacing theme token runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * 4px grid spacing scale for dense data tables.
 */
const SPACING_TOKENS = Object.freeze({
  primary: { value: "theme-spacing-primary", scope: "theme" },
  secondary: { value: "theme-spacing-secondary", scope: "theme" },
  muted: { value: "theme-spacing-muted", scope: "theme" },
  accent: { value: "theme-spacing-accent", scope: "theme" },
  surface: { value: "theme-spacing-surface", scope: "theme" },
});

const SPACING_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const SPACING_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const spacingRegistry = new Map();
const SPACING_listeners = new Set();
let SPACING_seq = 0;

function createSpacingId(prefix = "medx-theme-spacing") {
  SPACING_seq += 1;
  return `${prefix}-${SPACING_seq}`;
}

function registerSpacing(config = {}) {
  const entryId = config.id ?? createSpacingId();
  const preset = SPACING_PRESETS[config.preset ?? "default"] ?? SPACING_PRESETS.default;
  const token = SPACING_TOKENS[config.token ?? preset.token] ?? SPACING_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: SPACING_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  spacingRegistry.set(entryId, entry);
  notifySpacingListeners("register", entry);
  return entry;
}

function updateSpacing(id, patch = {}) {
  const entry = spacingRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifySpacingListeners("update", entry);
  return entry;
}

function resolveSpacing(id) {
  const entry = spacingRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listSpacingEntries(filter = {}) {
  let items = Array.from(spacingRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onSpacingEvent(listener) {
  SPACING_listeners.add(listener);
  return () => SPACING_listeners.delete(listener);
}

function notifySpacingListeners(type, entry) {
  for (const listener of SPACING_listeners) {
    try {
      listener({ type, entry, registrySize: spacingRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:theme:spacing] listener error", err.message);
    }
  }
}

function getSpacingMetrics() {
  const items = listSpacingEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(SPACING_TOKENS).length,
    presets: Object.keys(SPACING_PRESETS).length,
  };
}

async function runMedxSpacing() {
  console.log("[medx:ui:theme:spacing] runtime initialized");
  console.log(`[medx:ui:theme:spacing] tokens=${Object.keys(SPACING_TOKENS).length} presets=${Object.keys(SPACING_PRESETS).length}`);

  const events = [];
  onSpacingEvent((e) => events.push(e.type));

  const domains = Object.keys(SPACING_SUPPLY_CHAIN);
  const presets = Object.keys(SPACING_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerSpacing({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "theme/spacing" },
    });
  }

  const first = listSpacingEntries()[0];
  if (first) updateSpacing(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getSpacingMetrics();
  const resolved = first ? resolveSpacing(first.id) : null;

  console.log(`[medx:ui:theme:spacing] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:theme:spacing] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:theme:spacing] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:theme:spacing] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:theme:spacing] bootstrap complete");
}

module.exports = runMedxSpacing;
